	(37, 1, 'Botble\\ACL\\Models\\User', 'post', '{"name":"St. Catherine of Siena \\u2014 Doctor of the Church","model":"Botble\\\\Blog\\\\Models\\\\Post","slug":"st-catherine-of-siena-doctor-of-the-church","slug_id":"106","is_slug_editable":"1","description":"Catherine Benincasa was a lay member of the Dominican Order who lived during the 14th century. She is a Doctor of the Church and patron of Italy and Europe. Feast day: April 29.","is_featured":"1","content":"<p>Saint Catherine of Siena (1347\\u20131380) was an Italian tertiary of the Dominican Order and a Scholastic philosopher and theologian. She is venerated in the Catholic Church as a Doctor of the Church \\u2014 one of only four women to hold this title.<\\/p><p>Born the 24th child of a cloth dyer in Siena, she began having visions from the age of six. As a young woman she cared for the poor and sick in Siena before becoming an influential figure in Italian politics and in the Church.<\\/p><p>Her most notable letters were to Pope Gregory XI, whom she addressed bluntly as \\"Babbo\\" (father) and urged to return the papacy from Avignon to Rome \\u2014 which he ultimately did in 1377. Her major work, <i>The Dialogue of Divine Providence<\\/i> (or simply <i>The Dialogue<\\/i>), is a series of conversations between God the Father and a soul who represents Catherine herself.<\\/p><p>She was canonized by Pope Pius II in 1461, proclaimed a Doctor of the Church by Pope Paul VI in 1970, and named a patron of Europe by Pope John Paul II in 1999.<\\/p>","video_url":null,"audio":null,"note":null,"gallery":null,"seo_meta":{"seo_title":null,"seo_description":null,"index":"index"},"seo_meta_image":null,"status":"published","author_id":"1","categories":["3"],"image":"chatgpt-image-mar-28-2026-11-52-47-pm.png","time_to_read":null,"tag":"[{\\"value\\":\\"Saints\\"}]","allow_comments":"0","author_type":"Botble\\\\Member\\\\Models\\\\Member","submitter":"apply"}', 'updated', 'Mozilla/5.0 (Windows NT 10.0; Win64; x64; rv:149.0) Gecko/20100101 Firefox/149.0', '127.0.0.1', 1, 'Botble\\ACL\\Models\\User', 48, 'St. Catherine of Siena — Doctor of the Church', 'primary', '2026-03-28 21:55:51', '2026-03-28 21:55:51'),
	(38, 1, 'Botble\\ACL\\Models\\User', 'post', '{"name":"Holy Rosary with the Sorrowful Mysteries","model":"Botble\\\\Blog\\\\Models\\\\Post","slug":"holy-rosary-sorrowful-mysteries","slug_id":"80","is_slug_editable":"1","description":"Pray the Sorrowful Mysteries of the Holy Rosary. A guided meditation through the Passion of Christ.","is_featured":"0","content":"<p>The Rosary is one of the most beloved Catholic prayers. In this video, we meditate on the Sorrowful Mysteries: Agony in the Garden, Scourging at the Pillar, Crowning with Thorns, Carrying of the Cross, and Crucifixion.<\\/p>","video_url":"https:\\/\\/youtu.be\\/gTJ1bFapnhY?si=-2o0mf-cTuCCwbWl","audio":null,"note":null,"gallery":null,"seo_meta":{"seo_title":null,"seo_description":null,"index":"index"},"seo_meta_image":null,"status":"published","author_id":"1","categories":["9"],"image":"politics\\/news\\/2.jpg","time_to_read":null,"tag":"[{\\"value\\":\\"Rosary\\"},{\\"value\\":\\"Marian Devotions\\"}]","allow_comments":"0","author_type":"Botble\\\\Member\\\\Models\\\\Member"}', 'updated', 'Mozilla/5.0 (Windows NT 10.0; Win64; x64; rv:149.0) Gecko/20100101 Firefox/149.0', '127.0.0.1', 1, 'Botble\\ACL\\Models\\User', 22, 'Holy Rosary with the Sorrowful Mysteries', 'primary', '2026-03-28 22:43:12', '2026-03-28 22:43:12'),
