REPLACE INTO `youtube_channels` (`id`, `name`, `slug`, `youtube_channel_id`, `youtube_handle`, `uploads_playlist_id`, `thumbnail`, `banner`, `description`, `custom_url`, `is_active`, `sort_order`, `last_synced_at`, `created_at`, `updated_at`) VALUES
	(1, 'CatholicTV', 'catholictv', 'UCORAZZmab8apqy2TMHZlZVQ', '@CatholicTV', 'UUORAZZmab8apqy2TMHZlZVQ', 'https://yt3.ggpht.com/ytc/AIdro_mqZQR6hReIYjrPTb7-ecaoaQX-TIRxEeyb0Tpp13fxd-g=s800-c-k-c0x00ffffff-no-rj', 'https://yt3.googleusercontent.com/HSMGAarWU9bpvS4t3XWpbT4vZ16M81i2WOI5aljRDfRMt3eFQOjVAwLYZ5x2VT0SQRk22t5TqX8', 'Welcome to The CatholicTV Network YouTube channel! Here you’ll find our daily Masses, Catholic prayers, content from our broadcast TV shows, and original videos produced to help you live your faith more fully. Whether you’ve been Catholic for 85 years or have never set foot in a church, we’re here to serve you! Join us on YouTube and experience the goodness, beauty, and truth of Catholicism.', '@catholictv', 1, 1, '2026-03-29 09:33:10', '2026-03-29 09:18:49', '2026-03-29 09:33:10'),
	(2, 'EWTN', 'ewtn', 'UCijDos-LUTh9RQvSCMQqN6Q', '@EWTN', 'UUijDos-LUTh9RQvSCMQqN6Q', 'https://yt3.ggpht.com/-ViWxGG9QKwBOZPz0zKK60Hsyh6q-XQOtm__GvrFrblmFoiFoU1Pq0OgKo5R64hlIUvT6uCS=s800-c-k-c0x00ffffff-no-rj', 'https://yt3.googleusercontent.com/l6r8wqAX1OOQ8Mp_Uu26ioG74c4z1T8TgIVSjCrVQByp3lPDIB8mjZiqRjYsiUP1BGl8a8VP_Q', 'EWTN brings you powerful stories of faith, hope, and truth as you experience daily live Mass and Papal events with Pope Leo XIV, along with original series, news, and inspiring talks that connect Catholics around the world.\n\nWatch live coverage of Pope Leo XIV’s Mass, Angelus Prayer, and General Audience directly from Rome. Explore Catholic news, pray the Rosary, and discover faith-based documentaries that deepen your relationship with Christ.\n\nEWTN is the Global Catholic Network, sharing the Gospel through apologetics, Catholic teaching, and uplifting programming for every age and stage of life. Join millions of viewers worldwide and be part of a community united in faith.\n\nSubscribe and turn on notifications to grow in your Catholic faith every day.\n\nTo learn more about EWTN please visit https://www.ewtn.com\n', '@ewtn', 1, 2, '2026-03-29 09:33:13', '2026-03-29 09:18:49', '2026-03-29 09:33:13'),
	(3, 'Catholic Answers', 'catholic-answers', 'UCvwbLBTkuIwqNm9kHUqWRnw', NULL, 'UUvwbLBTkuIwqNm9kHUqWRnw', 'https://yt3.ggpht.com/hBdVHGntnxXAv9PhZit4VlpUCQhk9IT3KuXB36uO2WVi-xW6Lh5b2LEH6rsrRAtb4evYAO1fkPI=s800-c-k-c0x00ffffff-no-rj', 'https://yt3.googleusercontent.com/DamBn1XyM1T5FONtwnTxjPatnOFqMQIUCsO_7YFemdC5X7FkuRd2TL2dg0JReHEpsEl1ZjIJRjU', 'This is the main channel of Catholic Answers Live, hosted by Cy Kellett, is a daily, two-hour radio program dedicated to Catholic apologetics and evangelization. According to listener surveys, it is a runaway favorite on Catholic stations across America.\n\n📞 Have a question for the show? Call 888-318-7884 Weekdays from 3-5pm PT\n\nCatholic Answers Live connects callers to our five professional Catholic apologists Trent Horn, Jimmy Akin, Joe Heschmeyer, Karlo Broussard, and Tim Staples!\n\nYou’ll hear discussions on just about everything relating to the Church: doctrinal controversies, family concerns, social issues, evangelization, ethics…you name it!\n', '@ca-live', 1, 3, '2026-03-29 09:33:14', '2026-03-29 09:18:49', '2026-03-29 09:33:14'),
	(5, 'Ascension Presents', 'ascension-presents', 'UCVdGX3N-WIJ5nUvklBTNhAw', NULL, 'UUVdGX3N-WIJ5nUvklBTNhAw', 'https://yt3.ggpht.com/2mhKBivLUIgeKbZ70A7z-rv3DX-KSZsxL5UPSF8CvkKQ_TAITqgarHM2eCXbtgza1vYy_VAI=s800-c-k-c0x00ffffff-no-rj', 'https://yt3.googleusercontent.com/McPBOYxpIl_yeQ9UA0ZB6En1JZh2ORJj6IgqmYieVJRA2-6iCh5MIHIB1GQ7BONNpKycb0XfVA', 'Ascension Presents seeks to present the truth and beauty of the Catholic faith through media, and to answer the longings of the human heart with the transformative power of the Gospel. Visit www.ascensionpress.com to learn more.\n\nAscension Presents is owned and operated by Ascension Press.', '@ascensionpresents', 1, 5, '2026-03-29 09:33:18', '2026-03-29 09:18:49', '2026-03-29 09:33:18'),
	(6, 'The Coming Home Network', 'coming-home-network', 'UCIDebJFlV5aIsFs2jzxASrQ', NULL, 'UUIDebJFlV5aIsFs2jzxASrQ', 'https://yt3.ggpht.com/ytc/AIdro_noB7fj2gbyX_99upGGWSFEDvcv5KEKp7e8oqHXYlUHJYY=s800-c-k-c0x00ffffff-no-rj', 'https://yt3.googleusercontent.com/mGrbCT_n9kdSUyQQAKdunqVyV04sZ-9l961K_8qCDZiu07dXWjoE2T65_6TSOFB9Pw8tLavp3w', 'The Coming Home Network was established to help non-Catholic Christians, clergy and laity, discover the truth and beauty of Catholicism and to make the journey home to full communion with the Catholic Church.', '@cominghomenetwork', 1, 6, '2026-03-29 09:33:19', '2026-03-29 09:18:49', '2026-03-29 09:33:19'),
	(7, 'Bishop Robert Barron', 'bishop-barron', 'UCcMjLgeWNwqL2LBGS-iPb1A', NULL, 'UUcMjLgeWNwqL2LBGS-iPb1A', 'https://yt3.ggpht.com/yjqfvu6ZX2QWSqczNIi3sbN6224_O62eAFob7uLgomGEVG6es2Tc3i_RNjAa4TbJfrceWuHw8Q=s800-c-k-c0x00ffffff-no-rj', 'https://yt3.googleusercontent.com/uJKyA1bXFg6fw0HwwPRbWZxuZuY3ZIf5Qopw9V6ShRPPRns2JsEKnX12i1YvAVhbbGg-_IAzxA', 'These are brief and insightful commentaries on faith and culture by Catholic theologian and author Bishop Robert Barron.  The videos complement his weekly sermons posted and podcasted at WordOnFire.org.', '@bishopbarron', 1, 4, '2026-03-29 09:33:16', '2026-03-29 09:21:27', '2026-03-29 09:33:16');
