	(24, 1, 'L0GKhf_OF64', 'Scrolling at Night vs. Scrolling at Night', 'scrolling-at-night-vs-scrolling-at-night', 'Praying the rosary is the perfect way to wind down after a long day! Pray along with Bishop Reed on our YouTube channel, website, or any of our apps.', 'https://i.ytimg.com/vi/L0GKhf_OF64/maxresdefault.jpg', '2026-03-12 15:16:30', 'https://www.youtube.com/watch?v=L0GKhf_OF64', 'https://www.youtube.com/embed/L0GKhf_OF64', 'PT17S', 3755, 0, 23, '{"id": "L0GKhf_OF64", "etag": "0km8MYRiRrF59iOgZycVojyNc0Q", "kind": "youtube#video", "snippet": {"title": "Scrolling at Night vs. Scrolling at Night", "channelId": "UCORAZZmab8apqy2TMHZlZVQ", "localized": {"title": "Scrolling at Night vs. Scrolling at Night", "description": "Praying the rosary is the perfect way to wind down after a long day! Pray along with Bishop Reed on our YouTube channel, website, or any of our apps."}, "categoryId": "29", "thumbnails": {"high": {"url": "https://i.ytimg.com/vi/L0GKhf_OF64/hqdefault.jpg", "width": 480, "height": 360}, "maxres": {"url": "https://i.ytimg.com/vi/L0GKhf_OF64/maxresdefault.jpg", "width": 1280, "height": 720}, "medium": {"url": "https://i.ytimg.com/vi/L0GKhf_OF64/mqdefault.jpg", "width": 320, "height": 180}, "default": {"url": "https://i.ytimg.com/vi/L0GKhf_OF64/default.jpg", "width": 120, "height": 90}, "standard": {"url": "https://i.ytimg.com/vi/L0GKhf_OF64/sddefault.jpg", "width": 640, "height": 480}}, "description": "Praying the rosary is the perfect way to wind down after a long day! Pray along with Bishop Reed on our YouTube channel, website, or any of our apps.", "publishedAt": "2026-03-12T16:16:30Z", "channelTitle": "The CatholicTV Network", "defaultLanguage": "en", "defaultAudioLanguage": "en-US", "liveBroadcastContent": "none"}, "statistics": {"likeCount": "139", "viewCount": "3755", "commentCount": "3", "favoriteCount": "0"}, "contentDetails": {"caption": "false", "duration": "PT17S", "dimension": "2d", "definition": "hd", "projection": "rectangular", "co