	(116, 5, 'aQylATep4Yg', 'Former Protestant Pastor Returns to Catholic Faith (w/ Jeff Cavins) #shorts', 'former-protestant-pastor-returns-to-catholic-faith-w-jeff-cavins-shorts', '', 'https://i.ytimg.com/vi/aQylATep4Yg/maxresdefault.jpg', '2026-03-18 16:00:03', 'https://www.youtube.com/watch?v=aQylATep4Yg', 'https://www.youtube.com/embed/aQylATep4Yg', 'PT1M33S', 226763, 0, 19, '{"id": "aQylATep4Yg", "etag": "Vs1IDpIfrDg6SSAJ6Mgtcvhmmt4", "kind": "youtube#video", "snippet": {"title": "Former Protestant Pastor Returns to Catholic Faith (w/ Jeff Cavins) #shorts", "channelId": "UCVdGX3N-WIJ5nUvklBTNhAw", "localized": {"title": "Former Protestant Pastor Returns to Catholic Faith (w/ Jeff Cavins) #shorts", "description": ""}, "categoryId": "24", "thumbnails": {"high": {"url": "https://i.ytimg.com/vi/aQylATep4Yg/hqdefault.jpg", "width": 480, "height": 360}, "maxres": {"url": "https://i.ytimg.com/vi/aQylATep4Yg/maxresdefault.jpg", "width": 1280, "height": 720}, "medium": {"url": "https://i.ytimg.com/vi/aQylATep4Yg/mqdefault.jpg", "width": 320, "height": 180}, "default": {"url": "https://i.ytimg.com/vi/aQylATep4Yg/default.jpg", "width": 120, "height": 90}, "standard": {"url": "https://i.ytimg.com/vi/aQylATep4Yg/sddefault.jpg", "width": 640, "height": 480}}, "description": "", "publishedAt": "2026-03-18T17:00:03Z", "channelTitle": "Ascension Presents", "defaultLanguage": "en", "defaultAudioLanguage": "en-US", "liveBroadcastContent": "none"}, "statistics": {"likeCount": "8239", "viewCount": "226763", "commentCount": "275", "favoriteCount": "0"}, "contentDetails": {"caption": "false", "duration": "PT1M33S", "dimension": "2d", "definition": "hd", "projection": "rectangular", "contentRating": [], "licensedContent": true}}', '2026-03-29 09:21:37', '2026-03-29 09:33:19'),
	(117, 5, '4eyCVGOOmlI', 'If You\'re Doing This, It\'s Not Love (w/ Fr. Mike Schmitz)', 'if-youre-doing-this-its-not-love-w-fr-mike-schmitz', 'How many people do we pass by with indifference? How many do we see only for what they can do for us?\n\nFr. Mike Schmitz reminds us that the opposite of love is not hate, it\'s rather using others and being indifferent to them. He warns about how easily we can fall into these traps when our focus turns inward. When we become consumed with ourselves, we begin to overlook the inherent dignity of the people around us.\n\nFr. Mike challenges us to resist this tendency and instead choose to see, honor, and affirm the dignity of every human person.\n\nLet God lead you this Lent! Sign up for your most powerful Lent experience today! https://ascensionpress.com/pages/crux\n\n❓ Have ideas for future videos ❓ Topics you want to hear about ❓ Questions you want answered ❓ Make sure to put #AskAscension in your comment  👍\n\n—  MORE FROM ASCENSION  —\n\n🔸Ascension App: https://link.ascension-app.com/lMuyddWAqHb \n🔸The Great Adventure Bible: https://tinyurl.com/y6lfxzyt\n🔸 Catechism of the Catholic Church, Ascension Edition: https://tinyurl.com/25nskztb\n\n—  SOCIAL MEDIA  —\n\n🔸Facebook: https://www.facebook.com/AscensionPress/\n🔸Twitter: http://twitter.com/AscensionPress\n🔸LinkedIn:  https://www.linkedin.com/company/ascension-press\n🔸Instagram: http://www.instagram.com/ascensionpress/\n🔸Subscribe:   @AscensionPresents    \n\n—  BULLDOG CATHOLIC  —\n\n🔸YouTube: https://www.youtube.com/channel/UCXzB400_Skw95z2TmAsSkIg\n🔸iTunes: https://podcasts.apple.com/us/podcast/umd-newman-catholic-campus-ministry/id273537688\n\n11317200299', 'https://i.ytimg.com/vi/4eyCVGOOmlI/maxresdefault.jpg', '2026-03-18 15:00:16', 'https://www.youtube.com/watch?v=4eyCVGOOmlI', 'https://www.youtube.com/embed/4eyCVGOOmlI', 'PT7M46S', 119356, 0, 20, '{"id": "4eyCVGOOmlI", "etag": "fYgiJhEaKpQAWJCPr_AOtpF3JVA", "kind": "youtube#video", "snippet": {"tags": ["Fr. Mike",